import{_ as a,o as t,c as r,a0 as i}from"./chunks/framework.7S7UUFQz.js";const h=JSON.parse('{"title":"Release Governance","description":"","frontmatter":{},"headers":[],"relativePath":"release-governance.md","filePath":"release-governance.md"}'),o={name:"release-governance.md"};function d(c,e,n,s,l,p){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="release-governance" tabindex="-1">Release Governance <a class="header-anchor" href="#release-governance" aria-label="Permalink to &quot;Release Governance&quot;">​</a></h1><p>This page records the release governance checks that must stay green before a sprint item can be marked complete in the master checklist.</p><h2 id="package-boundaries" tabindex="-1">Package Boundaries <a class="header-anchor" href="#package-boundaries" aria-label="Permalink to &quot;Package Boundaries&quot;">​</a></h2><p><code>pnpm package:boundaries</code> is the automated boundary gate. It scans package manifests and <code>packages/*/src</code> imports so adapters, backend integrations, CLI code, and future game state cannot leak into lower-level packages.</p><p>The enforced source dependency direction is:</p><table tabindex="0"><thead><tr><th>Package</th><th>Allowed workspace imports</th></tr></thead><tbody><tr><td><code>@territory-kit/dataset</code></td><td>none</td></tr><tr><td><code>@territory-kit/core</code></td><td><code>@territory-kit/dataset</code></td></tr><tr><td><code>@territory-kit/generators</code></td><td><code>@territory-kit/core</code>, <code>@territory-kit/dataset</code></td></tr><tr><td><code>@territory-kit/maplibre</code></td><td><code>@territory-kit/core</code>, <code>@territory-kit/dataset</code></td></tr><tr><td><code>@territory-kit/nestjs</code></td><td><code>@territory-kit/core</code>, <code>@territory-kit/dataset</code></td></tr><tr><td><code>@territory-kit/cli</code></td><td><code>@territory-kit/core</code>, <code>@territory-kit/dataset</code>, <code>@territory-kit/generators</code></td></tr></tbody></table><p>Tests and examples can import higher-level packages when they are proving an integration flow.</p><h2 id="dataset-and-license-review" tabindex="-1">Dataset And License Review <a class="header-anchor" href="#dataset-and-license-review" aria-label="Permalink to &quot;Dataset And License Review&quot;">​</a></h2><p>Real dataset imports must record these facts before they are promoted from examples to maintained artifacts:</p><ul><li>Source name, owner, URL, retrieval date, and <code>sourceDate</code>.</li><li>Source license and whether redistribution, modification, and commercial use are permitted.</li><li>Any required attribution text.</li><li>Projection normalization to RFC 7946 longitude/latitude coordinates.</li><li>Geometry simplification steps and generated <code>geometryHash</code>.</li><li>Whether derived datasets can be published to npm or must remain documentation-only fixtures.</li></ul><p>Code license review is separate from dataset review. New code dependencies must be compatible with Apache-2.0 package publishing, while datasets must preserve their own attribution and redistribution rules.</p><h2 id="world-scale-data-roadmap" tabindex="-1">World-Scale Data Roadmap <a class="header-anchor" href="#world-scale-data-roadmap" aria-label="Permalink to &quot;World-Scale Data Roadmap&quot;">​</a></h2><p>World-scale support is deliberately staged after <code>1.0.0</code>:</p><ul><li>Keep <code>1.0.0</code> focused on viewport queries, simplification guidance, and benchmark evidence for synthetic 10K/100K datasets.</li><li>Add opt-in large benchmark evidence before marking 1M feature scenarios complete.</li><li>Add vector tile/MVT support in the <code>1.3</code> roadmap milestone rather than changing <code>territory-schema@1</code>.</li><li>Keep global administrative datasets out of MVP package publishing until source licensing and redistribution are reviewed.</li></ul><h2 id="validator-rules" tabindex="-1">Validator Rules <a class="header-anchor" href="#validator-rules" aria-label="Permalink to &quot;Validator Rules&quot;">​</a></h2><p>Cycle and orphan validation must stay schema-backed and repairable:</p><ul><li><code>parentId</code> cycles are hard validation errors.</li><li>Missing parent references are hard validation errors.</li><li>Non-reciprocal <code>neighborIds</code> are warnings so import pipelines can repair legacy adjacency data.</li><li>Repair suggestions should name the field, feature id, and source path when available.</li></ul><p>These rules keep dataset validation strict without making imperfect real-world import repair impossible.</p><h2 id="community-adapter-template" tabindex="-1">Community Adapter Template <a class="header-anchor" href="#community-adapter-template" aria-label="Permalink to &quot;Community Adapter Template&quot;">​</a></h2><p>The first community adapter template repo is a post-1.0 roadmap item. Until then, adapters should copy the MapLibre package shape:</p><ul><li>Keep renderer-specific code outside <code>@territory-kit/core</code>.</li><li>Depend only on <code>@territory-kit/core</code> and <code>@territory-kit/dataset</code>.</li><li>Provide capability metadata, lifecycle methods, theme/state update helpers, and visual or interaction tests for the target runtime.</li></ul><h2 id="feedback-and-security-channels" tabindex="-1">Feedback And Security Channels <a class="header-anchor" href="#feedback-and-security-channels" aria-label="Permalink to &quot;Feedback And Security Channels&quot;">​</a></h2><p>Release blockers are tracked through GitHub issues, PR review comments, or private security advisories when disclosure would be unsafe. Public issues are appropriate for documentation, compatibility, performance, and feature requests. Exploitable reports follow <code>SECURITY.md</code>.</p>',23)])])}const m=a(o,[["render",d]]);export{h as __pageData,m as default};
